class SensorFrame {
  final int rawTemperature;
  final int status;

  const SensorFrame(this.rawTemperature, this.status);
}

SensorFrame decodeSensorFrame(List<int> packet) {
  if (packet.length != 3) {
    throw FormatException('expected three-byte sensor packet');
  }
  final raw = packet[0] | (packet[1] << 8);
  return SensorFrame(raw, packet[2]);
}

