import 'packet_decoder.dart';

class SensorRegistry {
  final Set<String> activeIds;
  SensorRegistry(Iterable<String> ids) : activeIds = ids.toSet();

  bool contains(String id) => activeIds.contains(id);

  SensorFrame? decodeIfActive(String id, List<int> packet) {
    if (!contains(id)) return null;
    return decodeSensorFrame(packet);
  }
}

