import '../lib/sensor_registry.dart';
import '../lib/temperature.dart';

void check(bool condition, String message) {
  if (!condition) throw StateError(message);
}

void main() {
  final registry = SensorRegistry(['probe-a']);
  final frame = registry.decodeIfActive('probe-a', [0xc4, 0x09, 0x01]);
  check(frame != null && frame.rawTemperature == 2500, 'active positive raw value');
  check(temperatureCelsius(frame!) == 25.0, 'active positive domain value');
  check(registry.decodeIfActive('inactive', [0xc4, 0x09, 0x01]) == null, 'inactive routing');

  var malformedRejected = false;
  try {
    registry.decodeIfActive('probe-a', [0, 1]);
  } on FormatException {
    malformedRejected = true;
  }
  check(malformedRejected, 'packet length validation');
}
